"use client";

import { useMemo, useState } from "react";
import { DeptHeader } from "@/components/shared/DeptHeader";
import { AIStrip } from "@/components/shared/AIStrip";
import { SectionLabel } from "@/components/shared/SectionLabel";
import { BridgePrimaryButton } from "@/features/bridge/components/BridgePrimaryButton";
import {
  closeItems as INITIAL_ITEMS,
  closeMetrics,
  closeAI,
  type CloseItem,
} from "@/features/finance/api/finance-month-close-data";
import "./monthClose.css";

const CheckIcon = (
  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.4" strokeLinecap="round" strokeLinejoin="round">
    <path d="M5 12.5l4.5 4.5L19 7" />
  </svg>
);
const AlertIcon = (
  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.2" strokeLinecap="round" strokeLinejoin="round">
    <circle cx="12" cy="12" r="9" />
    <path d="M12 8v5M12 16.5v.01" />
  </svg>
);
const LockedPadlock = (
  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <rect x="5" y="11" width="14" height="9" rx="1.5" />
    <path d="M8 11V7a4 4 0 0 1 8 0v4" />
  </svg>
);
const OpenPadlock = (
  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
    <rect x="5" y="11" width="14" height="9" rx="1.5" />
    <path d="M8 11V8a4 4 0 0 1 7-2.6" />
  </svg>
);

export default function MonthClosePage() {
  const [items, setItems] = useState<CloseItem[]>(INITIAL_ITEMS);
  const [sentItem, setSentItem] = useState<string | null>(null);
  const [closed, setClosed] = useState(false);

  const blockers = useMemo(
    () => items.filter((it) => !it.done && !it.soft).length,
    [items],
  );
  const doneCount = useMemo(
    () => items.filter((it) => it.done || it.soft).length,
    [items],
  );
  const total = items.length;
  const ready = blockers === 0;

  const resolve = (key: string) => {
    setSentItem(key);
    setTimeout(() => {
      setItems((cur) => cur.map((it) => (it.key === key ? { ...it, done: true } : it)));
      setSentItem(null);
    }, 900);
  };

  const fireClose = () => {
    if (!ready) return;
    setClosed(true);
  };

  return (
    <div className="finance-month-close-page">
      <DeptHeader
        dept="finance"
        title="Month Close"
        meta={
          <>
            <span className="live">Live</span> · Clean, reconciled, ready to close · May 2026
          </>
        }
        actions={
          <>
            <button className="btn-util">Export draft →</button>
            <BridgePrimaryButton dept="finance">
              {closed ? "Month closed ✓" : "Close the month →"}
            </BridgePrimaryButton>
          </>
        }
      />
      <div className="head-pad" />

      {/* Metric strip */}
      <div className="metric-strip">
        <div className="metric">
          <div className="metric-l">Revenue · final</div>
          <div className="metric-v">{closeMetrics.revenue}</div>
          <div className="metric-s up">{closeMetrics.revenueDelta}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Total costs · final</div>
          <div className="metric-v">{closeMetrics.totalCosts}</div>
          <div className="metric-s">{closeMetrics.totalCostsPct}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Net profit · final</div>
          <div className="metric-v green">{closeMetrics.netProfit}</div>
          <div className="metric-s up">{closeMetrics.netMargin}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Days to close</div>
          <div className="metric-v">{closeMetrics.daysToClose}</div>
          <div className="metric-s">{closeMetrics.daysSubtitle}</div>
        </div>
        <div className="metric">
          <div className="metric-l">Close readiness</div>
          <div className={`metric-v ${ready ? "green" : "amber"}`}>
            {doneCount} / {total}
          </div>
          <div className="metric-s">
            {ready ? "All clear — ready to close" : `${blockers} item${blockers === 1 ? "" : "s"} need${blockers === 1 ? "s" : ""} attention`}
          </div>
        </div>
      </div>

      <AIStrip label={closeAI.label} meta={closeAI.meta} cards={closeAI.cards} />

      {/* Checklist */}
      <SectionLabel>Close checklist — what stands between you and a clean month</SectionLabel>
      <div className="checklist">
        {items.map((it) => {
          const ok = it.done;
          const stateCls = ok ? (it.soft ? "soft" : "ok") : "block";
          return (
            <div key={it.key} className={`cl-row ${stateCls}`}>
              <div className="cl-ico">{ok ? CheckIcon : AlertIcon}</div>
              <div>
                <div className="cl-label">{it.label}</div>
                <div className="cl-status">{ok ? it.doneText : it.blockText}</div>
              </div>
              <div className="cl-action">
                {!ok && (
                  <button
                    className={`cl-bridge${sentItem === it.key ? " sent" : ""}`}
                    onClick={() => resolve(it.key)}
                    type="button"
                  >
                    {sentItem === it.key ? "Sent ✓" : `${it.verb} → Bridge`}
                  </button>
                )}
              </div>
            </div>
          );
        })}
      </div>

      {/* The gate */}
      <div className={`gate${ready ? " ready" : ""}`}>
        <div className="gate-state">
          <div className="gate-ico">{ready ? OpenPadlock : LockedPadlock}</div>
          <div>
            <div className="gate-title">
              {ready
                ? "This month is ready to close"
                : `${blockers}${blockers === 1 ? " item still blocks" : " items still block"} the close`}
            </div>
            <div className="gate-sub">
              {ready
                ? "Everything is classified, reconciled, and approved. Closing locks the period and exports the clean books."
                : "Resolve the items above — the month can't close until the ledger is clean."}
            </div>
          </div>
        </div>
        <button
          className={`gate-btn${closed ? " done" : ""}`}
          onClick={fireClose}
          disabled={!ready || closed}
          type="button"
        >
          {closed ? "Month closed ✓" : "Close the month →"}
        </button>
      </div>

      {/* Final summary */}
      <SectionLabel>Final month summary — the clean number to send</SectionLabel>
      <div className="summary">
        <div className="sum-grid">
          <div className="sum-cell">
            <div className="sl">Revenue</div>
            <div className="sv">{closeMetrics.revenue}</div>
            <div className="ss">1,842 orders</div>
          </div>
          <div className="sum-cell">
            <div className="sl">Total costs</div>
            <div className="sv">{closeMetrics.totalCosts}</div>
            <div className="ss">COGS, ops, ads, overhead</div>
          </div>
          <div className="sum-cell anchor">
            <div className="sl">Net profit</div>
            <div className="sv green">{closeMetrics.netProfit}</div>
            <div className="ss green">{closeMetrics.netMargin}</div>
          </div>
        </div>
        <div className="sum-foot">
          <div className="sf-note">
            <span className={`sf-dot${ready ? " ok" : ""}`} />
            {ready
              ? "Reconciled with Xero · ready to export"
              : "Reconciled with Xero · pending final approval before export"}
          </div>
          <button className="btn-util sum-export" disabled={!ready} type="button">
            {closed ? "Exported ✓" : "Export to accountant →"}
          </button>
        </div>
      </div>
    </div>
  );
}
